import { useState } from 'react';
import { useNavigate } from 'react-router-dom';
import { useAuth } from '../context/AuthContext';
import axiosInstance from '../axiosConfig';

const emailRegex = /^[^\s@]+@[^\s@]+\.[^\s@]+$/;

export default function AdminLogin() {
  const navigate = useNavigate();
  const { login } = useAuth();

  const [formData, setFormData] = useState({
    adminId: '',
    email: '',
    password: '',
  });

  const [errorMessage, setErrorMessage] = useState('');
  const [isSubmitting, setIsSubmitting] = useState(false);

  // Update the form state and clear the current error message.
  const handleChange = (e) => {
    setErrorMessage('');
    setFormData((prev) => ({
      ...prev,
      [e.target.name]: e.target.value,
    }));
  };

  // Validate admin login fields before sending the request.
  const validateForm = () => {
    if (!formData.adminId.trim()) {
      return 'Please enter your admin ID.';
    }

    if (!emailRegex.test(formData.email.trim().toLowerCase())) {
      return 'Please enter a valid work email address.';
    }

    if (!formData.password || formData.password.length < 6) {
      return 'Please enter a valid password.';
    }

    return '';
  };

  const handleSubmit = async (e) => {
    e.preventDefault();

    const validationMessage = validateForm();
    if (validationMessage) {
      setErrorMessage(validationMessage);
      return;
    }

    try {
      setIsSubmitting(true);
      setErrorMessage('');

      const response = await axiosInstance.post('/api/auth/admin/login', {
        adminId: formData.adminId.trim(),
        email: formData.email.trim().toLowerCase(),
        password: formData.password,
      });

      // Save admin session data through the existing auth layer.
      login(response.data);

      // Redirect to the admin landing page after a successful login.
      navigate('/admin-profile');
    } catch (error) {
      const serverMessage =
        error?.response?.data?.message || 'Admin login failed. Please check your details and try again.';
      setErrorMessage(serverMessage);
    } finally {
      setIsSubmitting(false);
    }
  };

  return (
    <div className="min-h-screen bg-[#ececec] flex items-center justify-center px-4">
      <div className="w-[390px] min-h-[844px] bg-[#ececec] px-6 pt-6">
        <div className="flex items-center justify-between text-[14px] font-semibold text-black">
          <span>9:41</span>
          <div className="flex items-center gap-2">
            <div className="w-4 h-2 border border-black rounded-sm" />
            <div className="w-5 h-2 border border-black rounded-sm" />
            <div className="w-6 h-3 border border-black rounded-sm" />
          </div>
        </div>

        <div className="mt-16 flex flex-col items-center">
          <div className="w-[120px] h-[120px] rounded-full bg-white shadow-md flex items-center justify-center">
            <span className="text-[18px] font-bold text-[#4f4f4f]">Admin</span>
          </div>

          <h1 className="mt-6 text-[28px] font-bold text-black">Admin Login</h1>
          <p className="mt-2 text-[14px] text-gray-600">Welcome back to the management panel</p>
        </div>

        <form onSubmit={handleSubmit} className="mt-8">
          <div className="mb-4">
            <label className="block text-[14px] font-medium text-black mb-2">
              Admin ID
            </label>
            <input
              type="text"
              name="adminId"
              placeholder="Enter your admin ID"
              value={formData.adminId}
              onChange={handleChange}
              className="w-full h-[48px] rounded-[12px] border border-gray-300 px-4 outline-none"
              required
            />
          </div>

          <div className="mb-4">
            <label className="block text-[14px] font-medium text-black mb-2">
              Work Email
            </label>
            <input
              type="email"
              name="email"
              placeholder="Enter your work email"
              value={formData.email}
              onChange={handleChange}
              className="w-full h-[48px] rounded-[12px] border border-gray-300 px-4 outline-none"
              required
            />
          </div>

          <div className="mb-4">
            <label className="block text-[14px] font-medium text-black mb-2">
              Password
            </label>
            <input
              type="password"
              name="password"
              placeholder="Enter your password"
              value={formData.password}
              onChange={handleChange}
              className="w-full h-[48px] rounded-[12px] border border-gray-300 px-4 outline-none"
              required
            />
          </div>

          {errorMessage && (
            <div className="mb-4 rounded-[12px] bg-red-100 px-4 py-3 text-[13px] text-red-700">
              {errorMessage}
            </div>
          )}

          <button
            type="submit"
            disabled={isSubmitting}
            className="w-full h-[48px] rounded-[12px] bg-black text-white text-[18px] font-semibold disabled:opacity-70"
          >
            {isSubmitting ? 'Signing In...' : 'Log In'}
          </button>
        </form>

        <button
          type="button"
          onClick={() => navigate('/')}
          className="mt-8 w-full text-[15px] text-black underline"
        >
          Back to Welcome
        </button>
      </div>
    </div>
  );
}
